<template>
    <section class="main-content">
        <loader :is-visible="isLoading"></loader>

        <div class="padding-t_10 p-0" id="reportstabsdata">
            <!-- LEFT MENU -->
            <div class="left-menu-tab mt-2">
                <div class="col-md-12 p-0">
                    <div class="theme-primary partition">
                        <span class="p-name text-white">{{ $t("BillingRuleTemplate") }}</span>
                    </div>
                </div>

                <ul class="nav nav-pills flex-column left-tab mt-2 responivecustomtab nav-tabs">
                    <li
                        v-for="tab in tabs"
                        :key="tab.id"
                        @click="changeTab(tab)"
                        :class="{
                            'nav-item': true,
                            'active': currentTab.title === tab.title,
                            'disabled-tab': !tabsUnlocked && tab.title !== $t('BillingRuleConfiguration')
                        }"
                        :style="!tabsUnlocked && tab.title !== $t('BillingRuleConfiguration')
                            ? 'pointer-events:none;opacity:0.5;'
                            : ''"
                    >
                        <span
                            :class="{
                                'nav-link left-menu': true,
                                'active': currentTab.title === tab.title
                            }"
                        >
                            <i :class="tab.icon" class="p-1"></i>
                            {{ tab.displayName }}
                        </span>
                    </li>
                </ul>
            </div>

            <!-- RIGHT CONTENT -->
            <div class="right-content tablehead">
                <div class="tab-content z-indexfix">
                    <div class="expand-list">
                        <a href="javascript:;" class="expand-list-btn">
                            <i class="icon-solid arrow-solid-left text-white"></i>
                        </a>
                    </div>

                    <div class="theme-primary partition p-actions-expand mt-2" v-if="currentTab.title !== $t('LimitValue')">
                        <span class="p-name text-white">{{ billingRule }}</span>
                        <RouterLink to="/BillingRuleTemplate/RuleTemplateListing" >
                            <!-- <i class="fa fa-angle-double-left pr-2"></i><br> -->
                            <back></back>
                            <!-- {{ $t("BacktoList") }} -->
                        </RouterLink>
                        <a v-if="isBillingType && mode == 'Edit'"  @click="callSaveServiceRules" class="p-action-btn text-white float-right" :title="$t('Edit')">
                            <em class="fa fa-save"></em><br>
                            {{ $t("Save") }}
                        </a>
                        <a v-if="isBillingType && mode == 'Edit' && currentTab.title == $t('NodeConfiguration')" @click="callAddMoreRule" class="p-action-btn text-white float-right" :title="$t('AddMoreRule')">
                            <em class="fa fa-plus"></em><br>
                            {{ $t("AddMoreRule") }}
                        </a>
                        <a v-if="isBillingType && (mode == 'View'  || mode == 'Edit') && currentTab.title == $t('FlowChart1')" @click="callPrintVerticalFlow" 
                              class="p-action-btn text-white float-right" :title="$t('Print')">
                            <em class="fa fa-print"></em><br>
                            {{ $t("Print") }}
                        </a>
                        <a v-if="isBillingType && mode == 'View'" @click="EditRuleService" class="p-action-btn text-white float-right" :title="$t('Edit')">
                            <em class="fa fa-pencil"></em><br>
                            {{ $t("Edit") }}
                        </a>
                        <a v-if="currentTab.title === $t('OverrideCharge') && mode !== 'View'" @click="callAddNew"
                            class="p-action-btn text-white float-right" :title="$t('Add')">
                            <em class="fa fa-plus"></em><br>
                            {{ $t("Add") }}
                        </a>
                    </div>

                    <div 
                    :class="[
                            'col-md-12',
                            { 
                            border: currentTab.title !== $t('LimitValue'),
                            'float-left': currentTab.title !== $t('LimitValue')
                            }
                        ]"
                    
                    >
                        <BillingRuleTemplateConfiguration
                            v-if="currentTab.title === $t('BillingRuleConfiguration')"
                            :configurationId="configurationId"
                            :serviceId="serviceId"
                            :reqType="reqType"
                            :isBillingType="isBillingType"
                            @config-saved="handleSavedConfig"
                        />

                        <TemplateNodeConfiguration
                            v-if="currentTab.title === $t('NodeConfiguration')"
                            :configurationId="configurationId"
                            ref="nodeConfigRef"
                            :serviceId="serviceId"
                            :reqType="reqType"
                            :mode="mode"
                            :isBillingType="isBillingType"
                             :clientId="clientId"
                             :setupId="setupId"
                        />

                        <RuleTemplateLimit
                            v-if="currentTab.title === $t('LimitValue')"
                            :configurationId="configurationId"
                            :mode="mode"
                            :isBillingType="isBillingType"
                            :clientId="clientId" :billingRule="billingRule"
                        />

                        <OverrideCharges
                            v-if="currentTab.title === $t('OverrideCharge')"
                            ref="overrideChargesRef"
                            :configurationId="configurationId"
                            :mode="mode"
                            :isBillingType="isBillingType"
                            :clientId="clientId"
                        />

                        <VerticalFlowChart
                            v-if="currentTab.title === $t('FlowChart1')"
                            :configurationId="configurationId" ref="verticalFlowRef"
                            :isBillingType="isBillingType" :clientId="clientId"
                        />

                        <HorizontalFlowChart
                            v-if="currentTab.title === $t('FlowChart')"
                            :configurationId="configurationId"
                            :isBillingType="isBillingType"
                        />
                    </div>
                </div>
            </div>
        </div>
    </section>
</template>

<script>
import DataServices from "../../../services/DataService";
import BillingRuleTemplateConfiguration from "./RuleTemplateConfigurationComponent/BillingRuleTemplateConfiguration.vue";
import RuleTemplateLimit from "./RuleTemplateConfigurationComponent/RuleTemplateLimit.vue";
import TemplateNodeConfiguration from "./RuleTemplateConfigurationComponent/TemplateNodeConfiguration.vue";
import VerticalFlowChart from "../ConfigurationComponent/VerticalFlowChart.vue";
import OverrideCharges from "../ConfigurationComponent/OverrideCharges.vue";
import HorizontalFlowChart from "../ConfigurationComponent/HorizontalFlowChart.vue";

export default {
    components: {
        BillingRuleTemplateConfiguration,
        RuleTemplateLimit,
        TemplateNodeConfiguration,
        VerticalFlowChart,
        OverrideCharges,
        HorizontalFlowChart
    },

    props: {
        reqType: {
            type: String,
            required: false
        },
        configurationId: {
            type: Number,
            required: true
        },
        serviceId: {
            type: Number,
            required: true
        },
        mode: { type: String, default: "Edit" }
    },

    data() {
        return {
            tabsUnlocked: false,
            isLoading: false,
            isBillingType: false,
            configurationId: 0,
            clientId: null,
            mode: "Edit",
            billingRule:'',
            timeZone:'',
            tabs: [
                { id: 1, title: this.$t("BillingRuleConfiguration"), displayName: this.$t("BillingRuleConfiguration"), icon: "fa fa-cogs" },
                { id: 2, title: this.$t("NodeConfiguration"), displayName: this.$t("NodeConfiguration"), icon: "fa fa-xing" },
                { id: 3, title: this.$t("LimitValue"), displayName: this.$t("LimitValue"), icon: "fa fa-circle-o-notch" },
                { id: 4, title: this.$t("OverrideCharge"), displayName: this.$t("OverrideCharge"), icon: "fa fa-deviantart" },
                { id: 5, title: this.$t("FlowChart1"), displayName: this.$t("FlowChart1"), icon: "fa fa-usb" },
                { id: 6, title: this.$t("FlowChart"), displayName: this.$t("FlowChart"), icon: "fa fa-sitemap" }
            ],

            currentTab: null,
            setupId:0
        };
    },

    async created() {
        this.isBillingType = localStorage.getItem("billingType") === "USIC";
        this.mode = this.$route.params.mode || "Edit";
        this.configurationId = parseInt(this.$route.params.id);
        this.serviceId = parseInt(this.$route.params.serviceId);
        this.timeZone = this.GetUserInfo.TimeZone;
        if (this.configurationId) {
            this.tabsUnlocked = true;
            if (this.isBillingType) {
                 await this.BindConfigurationData(this.configurationId,this.serviceId,this.timeZone);
            }
        }

        this.currentTab =
            this.mode === "View" || this.mode === "Edit"
                ? this.tabs.find(t => t.title === this.$t("BillingRuleConfiguration"))
                : this.tabs[0];
    },

    watch: {
        "$route.params.id": async function (newId) {
            if (newId && this.isBillingType) {
                this.configurationId = parseInt(newId);
                await this.BindConfigurationData(this.configurationId,this.serviceId,this.timeZone);
            }
        }
    },

    methods: {
        callPrintVerticalFlow(){
            if (this.$refs.verticalFlowRef) {
                this.$refs.verticalFlowRef.printPage();
            }
        },
        callSaveServiceRules(){
            if (this.$refs.nodeConfigRef) {
                this.$refs.nodeConfigRef.saveServiceRules();
            }
        },
        callAddMoreRule() {
            if (this.$refs.nodeConfigRef) {
            this.$refs.nodeConfigRef.addMoreRule();
            }
        },
        EditRuleService: async function () {
            var vm = this;
            if(this.isBillingType){
                 vm.$router.push({ name: 'NodeTemplateConfiguration', params: { id: this.configurationId, serviceId : this.serviceId,mode :'Edit' } });
                 
            }
        },
         BindConfigurationData: async function (configurationId,serviceId,timeZone) {
            var vm = this;
            const url = `configrationId=${configurationId}&serviceId=${serviceId}&timezone=${timeZone}`;
            const response = await DataServices.BindBillingRuleTemplateById(url);
            if (response && response.data != null) {
                var configurationValue = response.data;
                vm.billingRule = configurationValue.billingTemplateName;
                vm.setupId = configurationValue.setupId;
            }
        },
        changeTab(tab) {
            if (!this.tabsUnlocked && tab.title !== this.$t("BillingRuleConfiguration")) return;
            this.currentTab = tab;
        },

        handleSavedConfig(payload) {
            this.configurationId = payload.configId;
            this.tabsUnlocked = true;

            if (payload.goTo) {
                const nextTab = this.tabs.find(t => t.title === this.$t(payload.goTo));
                if (nextTab) this.currentTab = nextTab;
            }
        },
        callAddNew() {
            this.$refs.overrideChargesRef?.AddNewRow?.();
        }
    }
};
</script>

<style scoped>
.disabled-tab {
    cursor: not-allowed;
}
</style>
